insert into public.exercise_library
  (name, category, why_it_matters, instructions, safety_notes, common_mistakes, regression, progression)
values
  ('Chair squat', 'legs', 'Builds leg strength for stairs, hills, disc golf rounds, and getting up easily.', 'Stand in front of a chair, sit back under control, pause lightly, then stand tall without rocking.', 'Keep the back quiet and avoid collapsing into the chair.', 'Rocking, knees diving inward, rushing the bottom.', 'Use a higher chair or hold a support.', 'Add reps first, then hold a light dumbbell.'),
  ('Goblet squat', 'legs', 'Builds stronger legs and hips while keeping the load easier to control.', 'Hold one dumbbell at chest height, sit between the hips, and stand tall.', 'Start light. Stop if back pain rises.', 'Dropping too deep too soon, rounding the back, bouncing.', 'Return to chair squats.', 'Add 5 pounds only after clean pain-free sets.'),
  ('Step-up', 'legs', 'Builds single-leg strength for hills, tee pads, and everyday durability.', 'Step onto a low platform, drive through the whole foot, and lower slowly.', 'Use a low step and hold support if balance is shaky.', 'Pushing off hard from the back leg or dropping down fast.', 'Use a lower step.', 'Add reps, then light dumbbells.'),
  ('Split squat', 'legs', 'Builds hips, knees, balance, and useful strength without heavy spinal loading.', 'Use a staggered stance, lower to a comfortable depth, and stand with control.', 'Hold onto something and keep range pain-free.', 'Going too deep, twisting, or losing balance.', 'Shorten the stance and reduce depth.', 'Add reps, then light dumbbells.'),
  ('Glute bridge', 'legs', 'Trains glutes to support the low back and hips.', 'Lie on your back, feet planted, squeeze glutes, and lift hips until straight.', 'Do not arch through the low back.', 'Overextending the spine or pushing through toes.', 'Use a smaller range of motion.', 'Pause longer at the top or add a light dumbbell.'),
  ('Dumbbell Romanian deadlift', 'legs', 'Teaches the hip hinge and strengthens hamstrings and glutes for back-safe progress.', 'Hold light dumbbells, push hips back, keep ribs down, and stand by squeezing glutes.', 'Very light at first. Avoid on days when back pain is 4 or higher.', 'Rounding the back, going too low, or chasing heavy weight.', 'Practice unloaded hip hinges with hands on hips.', 'Add 5 pounds only after pain-free, low-RPE sets.'),
  ('Incline push-up', 'push', 'Builds pressing strength without forcing risky shoulder depth.', 'Hands on bench, body straight, elbows 30 to 45 degrees, stop before shoulder pain.', 'Avoid deep range and flared elbows.', 'Letting shoulders shrug, flaring elbows, sagging hips.', 'Use a higher hand position.', 'Lower the incline slowly or add reps.'),
  ('Dumbbell floor press', 'push', 'Builds shoulder-smart pressing with the floor limiting depth.', 'Lie on the floor, press neutral-grip dumbbells, and stop with control.', 'No painful range. Keep elbows closer than a wide bench grip.', 'Flaring elbows or bouncing upper arms on the floor.', 'Use lighter dumbbells or one arm at a time.', 'Add small weight jumps after clean reps.'),
  ('One-arm dumbbell row', 'pull', 'Builds back strength and shoulder control for posture and disc golf resilience.', 'Support one hand on a bench, row smoothly, pause, and lower with control.', 'Keep torso stable and avoid twisting under load.', 'Yanking, rotating the torso, or shrugging.', 'Use lighter weight.', 'Add reps, then 5 pounds.'),
  ('Assisted pull-up', 'pull', 'Builds pulling strength without hanging from a vulnerable bottom position.', 'Use assistance, pull smoothly, and stop before the shoulder feels unstable.', 'No dead hang, no kipping, no painful range.', 'Dropping into the bottom or rushing reps.', 'Do one-arm rows instead.', 'Use slightly less assistance.'),
  ('Slow negative pull-up', 'pull', 'Builds pull-up strength with low volume and control.', 'Start at the top with support, lower slowly, and step down before a dead hang.', 'Only if the shoulder feels stable. Never drop into a dead hang.', 'Lowering too far or losing shoulder control.', 'Assisted pull-up or rows.', 'Add one controlled rep.'),
  ('Farmer carry', 'carry', 'Builds grip, trunk stiffness, posture, and useful dad strength.', 'Hold dumbbells at your sides and walk tall for time.', 'Stop if back pain rises or posture breaks.', 'Leaning back, rushing, or shrugging.', 'Use lighter weights or shorter rounds.', 'Add time before weight.'),
  ('Suitcase carry', 'carry', 'Builds anti-lean core strength for back resilience.', 'Hold one dumbbell in one hand and walk tall without leaning.', 'Use a moderate weight and keep the torso quiet.', 'Leaning away, twisting, or holding breath.', 'Use a lighter dumbbell.', 'Add time, then weight.'),
  ('Dead bug', 'core', 'Builds core control while protecting the low back.', 'Lie on your back, brace gently, move opposite arm and leg slowly, and keep back flat.', 'Reduce range if the low back arches.', 'Moving fast or letting ribs flare.', 'Move arms only or legs only.', 'Add longer reaches.'),
  ('Bird dog', 'core', 'Builds spine stability and hip control.', 'From hands and knees, reach opposite arm and leg, pause, and return slowly.', 'Keep hips level and avoid arching.', 'Rotating the hips or rushing.', 'Move only one limb at a time.', 'Add a longer pause.'),
  ('Front plank', 'core', 'Builds trunk endurance for a body you can trust.', 'Brace on forearms and toes, squeeze glutes, and breathe steadily.', 'Stop before low-back sagging or shoulder irritation.', 'Holding breath, sagging, or chasing time with bad form.', 'Use knees or an incline.', 'Add 5 to 10 seconds.'),
  ('Side plank', 'core', 'Builds lateral core strength for hips, back, and throwing resilience.', 'Brace on forearm and feet or knees, keep a straight line, and breathe.', 'Use the knee version if shoulder or back feels irritated.', 'Letting hips drop or shoulder shrug.', 'Side plank from knees.', 'Add time before harder variations.'),
  ('Cat-cow', 'mobility', 'Gives the spine gentle motion without loading it.', 'Move between rounded and extended positions slowly on hands and knees.', 'Stay gentle and avoid end-range pain.', 'Forcing range or moving too fast.', 'Use a smaller range.', 'Add slow breathing.'),
  ('Hip flexor stretch', 'mobility', 'Helps hips open up so the low back does not have to compensate.', 'Use a half-kneeling or standing stance, tuck pelvis slightly, and breathe.', 'Do not arch the low back.', 'Leaning back or forcing the stretch.', 'Do it standing.', 'Add a gentle glute squeeze.'),
  ('Hamstring stretch', 'mobility', 'Keeps posterior chain movement comfortable for walking and hinging.', 'Use a gentle position and hold without bouncing.', 'Avoid nerve-like symptoms or aggressive stretching.', 'Rounding hard through the low back.', 'Bend the knee.', 'Hold a little longer.'),
  ('Figure-four stretch', 'mobility', 'Helps glutes and hips feel better for walking and disc golf.', 'Cross one ankle over the opposite thigh and ease into the stretch.', 'Keep it comfortable for the low back.', 'Forcing the knee or twisting.', 'Do it seated.', 'Hold longer with calm breathing.'),
  ('Open book rotation', 'mobility', 'Improves upper-back rotation without loading the low back.', 'Lie on your side and rotate the top arm open with control.', 'This is gentle rotation, not twisting under load.', 'Forcing the shoulder or lumbar spine.', 'Use a smaller range.', 'Add slow breaths in the open position.'),
  ('Calf stretch', 'mobility', 'Supports walking volume, hills, and lower-leg comfort.', 'Press heel down with a straight or slightly bent knee and hold.', 'Avoid bouncing.', 'Turning the foot out or rushing.', 'Use a smaller lean.', 'Hold longer.')
on conflict (name) do update set
  category = excluded.category,
  why_it_matters = excluded.why_it_matters,
  instructions = excluded.instructions,
  safety_notes = excluded.safety_notes,
  common_mistakes = excluded.common_mistakes,
  regression = excluded.regression,
  progression = excluded.progression;

insert into public.goals
  (user_id, goal_name, current_value, first_target, strong_target, unit, category)
select id, goal_name, current_value, first_target, strong_target, unit, category
from public.profiles
cross join (
  values
    ('30-Second Chair Stand', 13, 20, 25, 'reps', 'legs'),
    ('Max Strict Push-Ups', 8, 20, 30, 'reps', 'push'),
    ('Max Strict Pull-Ups', 2.5, 5, 8, 'reps', 'pull'),
    ('Front Plank', 45, 75, 120, 'seconds', 'core'),
    ('Side Plank', 0, 30, 60, 'seconds each side', 'core'),
    ('Floor Get-Up Test', 0, 1, 1, 'smooth rep', 'mobility'),
    ('Farmer Carry', 0, 45, 60, 'lb dumbbells for 60s', 'carry'),
    ('Goblet Squat', 0, 40, 60, 'lb x 10', 'legs'),
    ('Bench Press', 0, 135, 185, 'lb', 'push')
) as g(goal_name, current_value, first_target, strong_target, unit, category)
where profiles.name = 'Dave'
on conflict (user_id, goal_name) do update set
  current_value = excluded.current_value,
  first_target = excluded.first_target,
  strong_target = excluded.strong_target,
  unit = excluded.unit,
  category = excluded.category;

insert into public.strength_tests
  (user_id, test_date, test_name, value, value_secondary, unit, quality, pain, notes)
select id, test_date::date, test_name, value, value_secondary, unit, quality, pain, notes
from public.profiles
cross join (
  values
    ('2026-05-02', '30-Second Chair Stand', 13, null, 'reps', 'imperfect', null, 'First test was imperfect because Dave rocked back up.'),
    ('2026-05-02', 'Max Strict Push-Ups', 8, null, 'reps', 'clean', 0, 'Weakness and burning felt mostly in shoulders.'),
    ('2026-05-02', 'Max Strict Pull-Ups', 2.5, null, 'reps', null, null, 'No dead hang because of left shoulder risk.'),
    ('2026-05-02', 'Front Plank', 45, null, 'seconds', 'shaky', null, null),
    ('2026-05-02', 'Side Plank', null, null, 'seconds', 'not tested', null, null)
) as t(test_date, test_name, value, value_secondary, unit, quality, pain, notes)
where profiles.name = 'Dave';

